function _updateEmptyState(count) {
  if (!_emptyState) return;
  if (count === 0) {
    _emptyState.removeAttribute('hidden');
    _emptyState.setAttribute('role', 'status');
    _emptyState.setAttribute('aria-live', 'polite');
    liveRegion.announce(STRINGS.noProductsFound || 'No products match the current filters.');
  } else {
    _emptyState.setAttribute('hidden', '');
  }
}
```

